// 1. Get value and trim whitespace
const val = components.inputConfigValue.value;
const value = (val !== undefined && val !== null) ? val.toString().trim() : "";

// 2. Fetch Type
const type = components.configTable.selectedRow.value_type;

let error = "";

// 3. Validation Logic (Empty value is now ALLOWED)
if (value !== "") { 
    // Only validate if there is actually text in the box
    switch (type) {
        case "VALUE_TYPE_INTEGER":
            if (!/^-?\d+$/.test(value)) error = "Invalid integer";
            break;

        case "VALUE_TYPE_FLOAT":
            if (!/^-?\d+(\.\d+)?$/.test(value)) error = "Invalid float (e.g. 1.2)";
            break;

        case "VALUE_TYPE_BOOLEAN":
            if (!/^(true|false)$/i.test(value)) error = "Enter 'true' or 'false'";
            break;

        case "VALUE_TYPE_ARRAY_STRING":
            if (!/^[^,]+(,\s*[^,]+)*$/.test(value)) error = "Invalid string array";
            break;

        case "VALUE_TYPE_ARRAY_INTEGER":
            if (!/^-?\d+(,\s*-?\d+)*$/.test(value)) error = "Invalid integer array";
            break;

        case "VALUE_TYPE_ARRAY_FLOAT":
            if (!/^-?\d+(\.\d+)?(,\s*-?\d+(\.\d+)?)*$/.test(value)) error = "Invalid float array";
            break;

        default:
            error = ""; 
            break;
    }
}

// 4. Update the UI variable
actions.setVariable("input_error", error);

// 5. Return result
return error === "";

