// 1. Get the type from the table (could be "String", "Integer", etc.)
const type = components.configTable.selectedRow.value_type;

const input = String(
  components.AddConfigValueForm.data.inputConfigValue?.value || ""
).trim();

let valuePayload = {};

// Use a "Contains" or "OR" check to be safe
// STRING
if (type === "VALUE_TYPE_STRING" || type === "String") {
  valuePayload.string_value = input;
}

// INTEGER
else if (type === "VALUE_TYPE_INTEGER" || type === "Integer") {
  if (!/^-?\d+$/.test(input)) {
    actions.setVariable("configValueError", "Please enter a valid integer");
    return;
  }
  valuePayload.int_value = Number(input);
}

// FLOAT
else if (type === "VALUE_TYPE_FLOAT" || type === "Float") {
  if (isNaN(Number(input))) {
    actions.setVariable("configValueError", "Please enter a valid float");
    return;
  }
  valuePayload.float_value = Number(input);
}

// BOOLEAN
else if (type === "VALUE_TYPE_BOOLEAN" || type === "Boolean") {
  const normalizedInput = input.toLowerCase();
  if (normalizedInput !== "true" && normalizedInput !== "false") {
    actions.setVariable("configValueError", "Enter true or false");
    return;
  }
  valuePayload.bool_value = normalizedInput === "true";
}

// ARRAY STRING
else if (type === "VALUE_TYPE_ARRAY_STRING" || type === "Array String") {
  valuePayload.array_string = {
    values: input.split(",").map(v => v.trim()).filter(Boolean)
  };
}

// ARRAY INTEGER
else if (type === "VALUE_TYPE_ARRAY_INTEGER" || type === "Array Integer") {
  const arr = input.split(",").map(v => v.trim());
  const invalid = arr.some(v => !/^-?\d+$/.test(v));
  if (invalid) {
    actions.setVariable("configValueError", "Array must contain integers only");
    return;
  }
  valuePayload.array_int = { values: arr.map(Number) };
}

// Finally set the variable
await actions.setVariable("configValuePayload", valuePayload);
actions.setVariable("configValueError", "");

// 1. Fetch Values from Form3
const rawConfig = components.form3.data.inputConfigValue.value;
const rawCanary = components.form3.data.inputCanaryValue.value;

const configValue = (rawConfig !== undefined && rawConfig !== null) ? rawConfig.toString().trim() : "";
const canaryValue = (rawCanary !== undefined && rawCanary !== null) ? rawCanary.toString().trim() : "";

// 2. Fetch Context from Table (Using your 'Tbale' typo from the screenshot)
const selectedRow = components.ConfigValueTbale.selectedRow;
const type = selectedRow?.value_type;
const isCanaryRow = selectedRow?.rollout_type === "ROLLOUT_TYPE_CANARY";

// 3. The "Smart" Validation Logic
const getValidationError = (val) => {
    if (val === "") return ""; 

    const parts = val.split(',').map(p => p.trim());
    // Ignore the very last part if it's empty (user is currently typing after a comma)
    const activeParts = (val.endsWith(',') && parts.length > 1) ? parts.slice(0, -1) : parts;
    const hasMiddleEmpty = parts.length > 1 && parts.slice(0, -1).some(p => p === "");

    switch (type) {
        case "VALUE_TYPE_INTEGER":
            return !/^-?\d+$/.test(val) ? "Must be a whole number" : "";

        case "VALUE_TYPE_FLOAT":
            return !/^-?\d+(\.\d+)?$/.test(val) ? "Must be a decimal (e.g. 1.2)" : "";

        case "VALUE_TYPE_BOOLEAN":
            return !/^(true|false)$/i.test(val) ? "Enter 'true' or 'false'" : "";

        case "VALUE_TYPE_ARRAY_STRING":
            return hasMiddleEmpty ? "Double commas not allowed" : "";

        case "VALUE_TYPE_ARRAY_INTEGER":
            if (hasMiddleEmpty) return "Double commas not allowed";
            const allInts = activeParts.every(p => /^-?\d+$/.test(p));
            return !allInts ? "All items must be integers" : "";

        case "VALUE_TYPE_ARRAY_FLOAT":
            if (hasMiddleEmpty) return "Double commas not allowed";
            const allFloats = activeParts.every(p => /^-?\d+(\.\d+)?$/.test(p));
            return !allFloats ? "All items must be decimals" : "";

        default:
            return "";
    }
};

// 4. Calculate Errors
const configErr = getValidationError(configValue);
const canaryErr = isCanaryRow ? getValidationError(canaryValue) : "";

// 5. Set Global Variables for the UI
await actions.setVariable("configError", configErr);
await actions.setVariable("canaryError", canaryErr);
await actions.setVariable("formHasError", (configErr !== "" || canaryErr !== ""));

// Return for debug preview
return { configErr, canaryErr, isCanaryRow, hasError: (configErr !== "" || canaryErr !== "") };

const count = parseInt(variables.dimensionCount || 0);

// FIX: Use the direct component path, not through the Form's data object
const listData = components.listview2.data || [];

// 1. Check if we already hit the limit
if (count >= 3) {
    return await actions.showAlert("info", "Maximum of 3 levels allowed.");
}

if (count === 0) {
    await actions.setVariable("dimensionCount", 1);
} else {
    // 2. Access 'Levels' (Capital L as seen in your Inspector screenshot)
    const lastRowValue = listData[count - 1]?.Levels?.value;

    // 3. Validation
    if (lastRowValue && String(lastRowValue).trim().length > 0) {
        await actions.setVariable("dimensionCount", count + 1);
    } else {
        await actions.showAlert("error", "Please fill Level " + count + " before adding another.");
    }
}

// 1. Get the name of the selected row from the table
const selectedConfigName = components.ConfigValueTbale.selectedRow?.config_name;

// 2. Find the original "Clean" data from your JS Query
// NOTE: Ensure the query name below matches exactly (case sensitive)
const allData = queries.transformTabledata.data || []; 
const originalRow = allData.find(row => row.config_name === selectedConfigName);

// --- Handle Dimensions ---
// Pull from originalRow so we get the actual Array
const dimensionsArray = Array.isArray(originalRow?.dimensions) ? originalRow.dimensions : [];

// --- Handle Rollout Type ---
// Use the new Key Name "Rollout Type" with brackets because of the space
