const finalRollout = (displayRollout === "Canary" || displayRollout === "ROLLOUT_TYPE_CANARY")
  ? "ROLLOUT_TYPE_CANARY" 
  : "ROLLOUT_TYPE_UNSPECIFIED";

// --- Set Variables ---
