await actions.setVariable("DimensionArray", dimensionsArray);

return {
  dimensions: dimensionsArray,
  rollout: finalRollout,
  foundRow: !!originalRow
};

const dimensions = [];
// Fix: Use direct path to the dropdown
const paramType = components.dropdownParamType.value; 

if (paramType === "PARAM_TYPE_HIERARCHICAL") {

  // 1. Get the data. Fix: Use direct path to listview2
  const listDataObject = components.listview2.data || {};

  // 2. Convert the Object into an Array so we can loop through it
  const rows = Object.values(listDataObject);

  // 3. Loop through the rows
  rows.forEach((row) => {
    // Note: Use 'Levels' with a Capital L as seen in your inspector
    const val = row.Levels?.value;

    if (val && String(val).trim() !== "") {
      dimensions.push(val.trim());
    }
  });
}

// 4. Set the variable
await actions.setVariable("dimensionsArray", dimensions);

return dimensions;

actions.setVariable("isAdminList", [
  "aakash.lokhande@truemeds.in"
]);

const rawData = queries.ListConfigValue.data?.config_values || [];

const formatValue = (obj) => {
  if (!obj) return "";
  if (obj.string_value !== undefined) return obj.string_value;
  if (obj.int_value !== undefined) return obj.int_value;
  if (obj.float_value !== undefined) return obj.float_value;
  if (obj.bool_value !== undefined) return String(obj.bool_value);
  if (obj.array_string?.values) return obj.array_string.values.join(", ");
  if (obj.array_int?.values) return obj.array_int.values.join(", ");
  if (obj.array_float?.values) return obj.array_float.values.join(", ");
  return "";
};

const formatDate = (timeObj) => {
  if (!timeObj || !timeObj.seconds) return "N/A";
  return new Date(Number(timeObj.seconds) * 1000).toLocaleString(); 
};

return rawData.map(row => {
  return {
    "config_name": row.config_name,
    "Value": formatValue(row.value),
    "Canary Value": formatValue(row.canary_value), 
    "canary percentage": row.canary_param?.percentage !== undefined ? row.canary_param.percentage + "%" : "0%",
    "Updated At": formatDate(row.updated_at),
    "Rollout Type": row.rollout_type,
    dimensions: row.dimensions || []
  };
});

const currentCount = parseInt(variables.dimensionCount || 0);

if (currentCount > 1) {
    // This removes the last row
    await actions.setVariable("dimensionCount", currentCount - 1);
} else {
    // Don't let them delete the last remaining row, just clear it
    await actions.showAlert("info", "At least one level is required.");
}
